import requests
import json
import time
from typing import Dict, List, Optional, Any


class KongAdminAPI:
    def __init__(self, admin_url: str = "http://localhost:8001"):
        self.admin_url = admin_url.rstrip('/')
        self.session = requests.Session()
        self.session.headers.update({'Content-Type': 'application/json'})

    def _make_request(self, method: str, endpoint: str, data: Optional[Dict] = None) -> Dict:
        url = f"{self.admin_url}/{endpoint}"
        try:
            if method == 'GET':
                response = self.session.get(url)
            elif method == 'POST':
                response = self.session.post(url, json=data)
            elif method == 'PUT':
                response = self.session.put(url, json=data)
            elif method == 'PATCH':
                response = self.session.patch(url, json=data)
            elif method == 'DELETE':
                response = self.session.delete(url)
            else:
                raise ValueError(f"Unsupported HTTP method: {method}")
            
            response.raise_for_status()
            return response.json() if response.text else {}
        except requests.exceptions.RequestException as e:
            print(f"Error making {method} request to {url}: {e}")
            if hasattr(e, 'response') and e.response is not None:
                print(f"Response: {e.response.text}")
            raise

    def create_service(self, name: str, url: str, **kwargs) -> Dict:
        data = {
            'name': name,
            'url': url
        }
        data.update(kwargs)
        return self._make_request('POST', 'services', data)

    def get_service(self, service_name_or_id: str) -> Dict:
        return self._make_request('GET', f'services/{service_name_or_id}')

    def update_service(self, service_name_or_id: str, **kwargs) -> Dict:
        return self._make_request('PATCH', f'services/{service_name_or_id}', kwargs)

    def delete_service(self, service_name_or_id: str) -> Dict:
        return self._make_request('DELETE', f'services/{service_name_or_id}')

    def list_services(self) -> List[Dict]:
        response = self._make_request('GET', 'services')
        return response.get('data', [])

    def create_route(self, service_name_or_id: str, paths: List[str] = None, 
                     hosts: List[str] = None, methods: List[str] = None, **kwargs) -> Dict:
        data = {}
        if paths:
            data['paths'] = paths
        if hosts:
            data['hosts'] = hosts
        if methods:
            data['methods'] = methods
        data.update(kwargs)
        return self._make_request('POST', f'services/{service_name_or_id}/routes', data)

    def get_route(self, route_id: str) -> Dict:
        return self._make_request('GET', f'routes/{route_id}')

    def update_route(self, route_id: str, **kwargs) -> Dict:
        return self._make_request('PATCH', f'routes/{route_id}', kwargs)

    def delete_route(self, route_id: str) -> Dict:
        return self._make_request('DELETE', f'routes/{route_id}')

    def list_routes(self, service_name_or_id: Optional[str] = None) -> List[Dict]:
        if service_name_or_id:
            response = self._make_request('GET', f'services/{service_name_or_id}/routes')
        else:
            response = self._make_request('GET', 'routes')
        return response.get('data', [])

    def create_upstream(self, name: str, **kwargs) -> Dict:
        data = {'name': name}
        data.update(kwargs)
        return self._make_request('POST', 'upstreams', data)

    def get_upstream(self, upstream_name_or_id: str) -> Dict:
        return self._make_request('GET', f'upstreams/{upstream_name_or_id}')

    def update_upstream(self, upstream_name_or_id: str, **kwargs) -> Dict:
        return self._make_request('PATCH', f'upstreams/{upstream_name_or_id}', kwargs)

    def delete_upstream(self, upstream_name_or_id: str) -> Dict:
        return self._make_request('DELETE', f'upstreams/{upstream_name_or_id}')

    def list_upstreams(self) -> List[Dict]:
        response = self._make_request('GET', 'upstreams')
        return response.get('data', [])

    def create_target(self, upstream_name_or_id: str, target: str, weight: int = 100, **kwargs) -> Dict:
        data = {
            'target': target,
            'weight': weight
        }
        data.update(kwargs)
        return self._make_request('POST', f'upstreams/{upstream_name_or_id}/targets', data)

    def list_targets(self, upstream_name_or_id: str) -> List[Dict]:
        response = self._make_request('GET', f'upstreams/{upstream_name_or_id}/targets')
        return response.get('data', [])

    def delete_target(self, upstream_name_or_id: str, target_id: str) -> Dict:
        return self._make_request('DELETE', f'upstreams/{upstream_name_or_id}/targets/{target_id}')

    def add_plugin(self, plugin_name: str, service_id: Optional[str] = None, 
                   route_id: Optional[str] = None, consumer_id: Optional[str] = None,
                   config: Optional[Dict] = None, **kwargs) -> Dict:
        data = {'name': plugin_name}
        if service_id:
            data['service'] = {'id': service_id}
        if route_id:
            data['route'] = {'id': route_id}
        if consumer_id:
            data['consumer'] = {'id': consumer_id}
        if config:
            data['config'] = config
        data.update(kwargs)
        return self._make_request('POST', 'plugins', data)

    def list_plugins(self) -> List[Dict]:
        response = self._make_request('GET', 'plugins')
