def setup_example_infrastructure(kong: KongAdminAPI):
    print("Setting up Kong infrastructure...")
    
    print("\n1. Creating upstream 'api-backend'...")
    upstream = kong.create_upstream(
        name='api-backend',
        algorithm='round-robin',
        slots=10000
    )
    print(f"Created upstream: {upstream['name']} (ID: {upstream['id']})")
    
    print("\n2. Adding targets to upstream...")
    targets = [
        ('backend-1.example.com:8080', 100),
        ('backend-2.example.com:8080', 100),
        ('backend-3.example.com:8080', 50)
    ]
    
    for target_url, weight in targets:
        target = kong.create_target('api-backend', target_url, weight=weight)
        print(f"Added target: {target['target']} with weight {target['weight']}")
    
    print("\n3. Creating service 'my-api-service'...")
    service = kong.create_service(
        name='my-api-service',
        host='api-backend',
        port=80,
        protocol='http',
        path='/api',
        connect_timeout=60000,
        write_timeout=60000,
        read_timeout=60000,
        retries=5
    )
    print(f"Created service: {service['name']} (ID: {service['id']})")
    
    print("\n4. Creating routes for the service...")
    route1 = kong.create_route(
        service_name_or_id='my-api-service',
        paths=['/api/v1', '/api/v2'],
        methods=['GET', 'POST', 'PUT', 'DELETE'],
        strip_path=True,
        preserve_host=False
    )
    print(f"Created route: {route1['id']} with paths {route1['paths']}")
    
    route2 = kong.create_route(
        service_name_or_id='my-api-service',
        hosts=['api.example.com'],
        methods=['GET', 'POST']
    )
    print(f"Created route: {route2['id']} with hosts {route2['hosts']}")
    
    print("\n5. Adding plugins...")
    
    rate_limit_plugin = kong.add_plugin(
        plugin_name='rate-limiting',
        service_id=service['id'],
        config={
            'minute': 100,
            'hour': 5000,
            'policy': 'local'
        }
    )
    print(f"Added rate-limiting plugin: {rate_limit_plugin['id']}")
    
    cors_plugin = kong.add_plugin(
        plugin_name='cors',
        service_id=service['id'],
        config={
            'origins': ['*'],
            'methods': ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS'],
            'headers': ['Accept', 'Content-Type', 'Authorization'],
            'exposed_headers': ['X-Auth-Token'],
            'credentials': True,
            'max_age': 3600
        }
    )
    print(f"Added CORS plugin: {cors_plugin['id']}")
    
    print("\n6. Creating another service with upstream...")
    auth_service = kong.create_service(
        name='auth-service',
        url='http://auth.example.com:3000/auth'
    )
    print(f"Created service: {auth_service['name']} (ID: {auth_service['id']})")
    
    auth_route = kong.create_route(
        service_name_or_id='auth-service',
        paths=['/auth'],
        strip_path=False
    )
    print(f"Created route: {auth_route['id']} for auth service")
    
    print("\n7. Creating consumer...")
    consumer = kong.create_consumer(
        username='test-user',
        custom_id='user-123'
    )
    print(f"Created consumer: {consumer['username']} (ID: {consumer['id']})")
    
    print("\n=== Configuration Summary ===")
    print(f"\nServices:")
    for svc in kong.list_services():
        print(f"  - {svc['name']}: {svc.get('host', svc.get('url', 'N/A'))}")
    
    print(f"\nUpstreams:")
    for ups in kong.list_upstreams():
        print(f"  - {ups['name']} (algorithm: {ups['algorithm']})")
        targets_list = kong.list_targets(ups['name'])
        for tgt in targets_list:
            print(f"    -> {tgt['target']} (weight: {tgt['weight']})")
    
    print(f"\nRoutes:")
    for rt in kong.list_routes():
        print(f"  - {rt['id']}")
        if rt.get('paths'):
            print(f"    Paths: {rt['paths']}")
        if rt.get('hosts'):
            print(f"    Hosts: {rt['hosts']}")
        if rt.get('methods'):
            print(f"    Methods: {rt['methods']}")
    
    print(f"\nPlugins:")
    for plg in kong.list_plugins():
        print(f"  - {plg['name']} (ID: {plg['id']})")
    
    print(f"\nConsumers:")
    for cons in kong.list_consumers():
        print(f"  - {cons['username']} (ID: {cons['id']})")


def main():
    kong_admin_url = "http://localhost:8001"
    
    kong = KongAdminAPI(admin_url=kong_admin_url)
    
    try:
        status = kong.get_status()
        print(f"Kong is running. Database: {status.get('database', {}).get('reachable', False)}")
        print(f"Server: {status.get('server', {})}")
    except Exception as e:
        print(f"Failed to connect to Kong Admin API at {kong_admin_url}")
        print(f"Error: {e}")
        print("Please ensure Kong is running and accessible.")
        return
    
    setup_example_infrastructure(kong)
    
    print("\n\nKong configuration completed successfully!")


if __name__ == "__main__":
    main()